import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, useNavigate } from 'react-router-dom';
import io from 'socket.io-client';
import axios from 'axios';

const socket = io('http://localhost:5001');

// --- COMPONENTS ---

const Login = ({ setAuth }) => {
  const navigate = useNavigate();
  const handleLogin = () => {
    // In a real app, verify with Backend. For testing, we simulate:
    setAuth(true);
    navigate('/dashboard');
  };
  return (
    <div style={{ textAlign: 'center', marginTop: '100px' }}>
      <h2>Buyer Login</h2>
      <button onClick={handleLogin} style={{ padding: '10px 20px', cursor: 'pointer' }}>Login with Gmail (Simulated)</button>
    </div>
  );
};

const RegisterDevice = () => {
  const [id, setId] = useState('');
  const handleAdd = () => {
    alert(`Device ${id} Registered! Make sure your Python script uses this ID.`);
  };
  return (
    <div style={{ padding: '20px' }}>
      <h3>Register New Edge Device</h3>
      <input placeholder="Enter MAC or Device ID" onChange={(e)=>setId(e.target.value)} />
      <button onClick={handleAdd}>Add Device</button>
    </div>
  );
};

const Dashboard = () => {
  const [incidents, setIncidents] = useState([]);
  const [deviceStatus, setDeviceStatus] = useState("Offline");

  useEffect(() => {
    socket.on(`alert-BUS_A12`, (data) => {
      setDeviceStatus("Online");
      setIncidents(prev => [data, ...prev]);
    });
  }, []);

  return (
    <div style={{ padding: '20px' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between' }}>
        <h2>Live Bus Dashboard</h2>
        <span style={{ color: deviceStatus === "Online" ? "green" : "red" }}>● Device: {deviceStatus}</span>
      </div>
      <table border="1" width="100%" style={{ marginTop: '20px' }}>
        <thead><tr><th>Time</th><th>Incident</th><th>Link</th></tr></thead>
        <tbody>
          {incidents.map((inc, i) => (
            <tr key={i}>
              <td>{new Date(inc.timestamp * 1000).toLocaleTimeString()}</td>
              <td>{inc.event}</td>
              <td><a href={inc.videoUrl} target="_blank">View on Drive</a></td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

// --- MAIN APP STRUCTURE ---

export default function App() {
  const [isAuth, setIsAuth] = useState(false);

  return (
    <Router>
      <nav style={{ padding: '10px', background: '#222', color: '#fff' }}>
        <Link to="/" style={{ color: '#fff', marginRight: '15px' }}>Home</Link>
        {isAuth && <Link to="/register" style={{ color: '#fff', marginRight: '15px' }}>Register Device</Link>}
        {isAuth && <Link to="/dashboard" style={{ color: '#fff' }}>Dashboard</Link>}
      </nav>

      <Routes>
        <Route path="/" element={<Login setAuth={setIsAuth} />} />
        <Route path="/register" element={<RegisterDevice />} />
        <Route path="/dashboard" element={<Dashboard />} />
      </Routes>
    </Router>
  );
}
